50: /**
51:  * SaslServer implementation for SASL/SCRAM. This server is configured with a callback
52:  * handler for integration with a credential manager. Kafka brokers provide callbacks
53:  * based on a Zookeeper-based password store.
54:  *
55:  * @see <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>
56:  */
57: public class ScramSaslServer implements SaslServer {
58: 
59:     private static final Logger log = LoggerFactory.getLogger(ScramSaslServer.class);
60:     private static final Set<String> SUPPORTED_EXTENSIONS = Utils.mkSet(ScramLoginModule.TOKEN_AUTH_CONFIG);
61: 
62:     enum State {
63:         RECEIVE_CLIENT_FIRST_MESSAGE,
64:         RECEIVE_CLIENT_FINAL_MESSAGE,
65:         COMPLETE,
66:         FAILED
67:     }
68: 
69:     private final ScramMechanism mechanism;
70:     private final ScramFormatter formatter;
71:     private final CallbackHandler callbackHandler;
72:     private State state;
73:     private String username;
74:     private ClientFirstMessage clientFirstMessage;
75:     private ServerFirstMessage serverFirstMessage;
76:     private ScramExtensions scramExtensions;
77:     private ScramCredential scramCredential;
78:     private String authorizationId;
79:     private Long tokenExpiryTimestamp;
80: 
81:     public ScramSaslServer(ScramMechanism mechanism, Map<String, ?> props, CallbackHandler callbackHandler) throws NoSuchAlgorithmException {
82:         this.mechanism = mechanism;
83:         this.formatter = new ScramFormatter(mechanism);
84:         this.callbackHandler = callbackHandler;
85:         setState(State.RECEIVE_CLIENT_FIRST_MESSAGE);
86:     }
87: 
88:     /**
89:      * @throws SaslAuthenticationException if the requested authorization id is not the same as username.
90:      * <p>
91:      * <b>Note:</b> This method may throw {@link SaslAuthenticationException} to provide custom error messages
92:      * to clients. But care should be taken to avoid including any information in the exception message that
93:      * should not be leaked to unauthenticated clients. It may be safer to throw {@link SaslException} in
94:      * most cases so that a standard error message is returned to clients.
95:      * </p>
96:      */
97:     @Override
98:     public byte[] evaluateResponse(byte[] response) throws SaslException, SaslAuthenticationException {
99:         try {
100:             switch (state) {
101:                 case RECEIVE_CLIENT_FIRST_MESSAGE:
102:                     this.clientFirstMessage = new ClientFirstMessage(response);
103:                     this.scramExtensions = clientFirstMessage.extensions();
104:                     if (!SUPPORTED_EXTENSIONS.containsAll(scramExtensions.map().keySet())) {
105:                         log.debug("Unsupported extensions will be ignored, supported {}, provided {}",
106:                                 SUPPORTED_EXTENSIONS, scramExtensions.map().keySet());
107:                     }
108:                     String serverNonce = formatter.secureRandomString();
109:                     try {
110:                         String saslName = clientFirstMessage.saslName();
111:                         this.username = ScramFormatter.username(saslName);
112:                         NameCallback nameCallback = new NameCallback("username", username);
113:                         ScramCredentialCallback credentialCallback;
114:                         if (scramExtensions.tokenAuthenticated()) {
115:                             DelegationTokenCredentialCallback tokenCallback = new DelegationTokenCredentialCallback();
116:                             credentialCallback = tokenCallback;
117:                             callbackHandler.handle(new Callback[]{nameCallback, tokenCallback});
118:                             if (tokenCallback.tokenOwner() == null)
119:                                 throw new SaslException("Token Authentication failed: Invalid tokenId : " + username);
120:                             this.authorizationId = tokenCallback.tokenOwner();
121:                             this.tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
122:                         } else {
123:                             credentialCallback = new ScramCredentialCallback();
124:                             callbackHandler.handle(new Callback[]{nameCallback, credentialCallback});
125:                             this.authorizationId = username;
126:                             this.tokenExpiryTimestamp = null;
127:                         }
128:                         this.scramCredential = credentialCallback.scramCredential();
129:                         if (scramCredential == null)
130:                             throw new SaslException("Authentication failed: Invalid user credentials");
131:                         String authorizationIdFromClient = clientFirstMessage.authorizationId();
132:                         if (!authorizationIdFromClient.isEmpty() && !authorizationIdFromClient.equals(username))
133:                             throw new SaslAuthenticationException("Authentication failed: Client requested an authorization id that is different from username");
134: 
135:                         if (scramCredential.iterations() < mechanism.minIterations())
136:                             throw new SaslException("Iterations " + scramCredential.iterations() +  " is less than the minimum " + mechanism.minIterations() + " for " + mechanism);
137:                         this.serverFirstMessage = new ServerFirstMessage(clientFirstMessage.nonce(),
138:                                 serverNonce,
139:                                 scramCredential.salt(),
140:                                 scramCredential.iterations());
141:                         setState(State.RECEIVE_CLIENT_FINAL_MESSAGE);
142:                         return serverFirstMessage.toBytes();
143:                     } catch (SaslException | AuthenticationException e) {
144:                         throw e;
145:                     } catch (Throwable e) {
146:                         throw new SaslException("Authentication failed: Credentials could not be obtained", e);
147:                     }
148: 
149:                 case RECEIVE_CLIENT_FINAL_MESSAGE:
150:                     try {
151:                         ClientFinalMessage clientFinalMessage = new ClientFinalMessage(response);
152:                         verifyClientProof(clientFinalMessage);
153:                         byte[] serverKey = scramCredential.serverKey();
154:                         byte[] serverSignature = formatter.serverSignature(serverKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
155:                         ServerFinalMessage serverFinalMessage = new ServerFinalMessage(null, serverSignature);
156:                         clearCredentials();
157:                         setState(State.COMPLETE);
158:                         return serverFinalMessage.toBytes();
159:                     } catch (InvalidKeyException e) {
160:                         throw new SaslException("Authentication failed: Invalid client final message", e);
161:                     }
162: 
163:                 default:
164:                     throw new IllegalSaslStateException("Unexpected challenge in Sasl server state " + state);
165:             }
166:         } catch (SaslException | AuthenticationException e) {
167:             clearCredentials();
168:             setState(State.FAILED);
169:             throw e;
170:         }
171:     }
172: 
173:     @Override
174:     public String getAuthorizationID() {
175:         if (!isComplete())
176:             throw new IllegalStateException("Authentication exchange has not completed");
177:         return authorizationId;
178:     }
179: 
180:     @Override
181:     public String getMechanismName() {
182:         return mechanism.mechanismName();
183:     }
184: 
185:     @Override
186:     public Object getNegotiatedProperty(String propName) {
187:         if (!isComplete())
188:             throw new IllegalStateException("Authentication exchange has not completed");
189:         if (SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY.equals(propName))
190:             return tokenExpiryTimestamp; // will be null if token not used
191:         if (SUPPORTED_EXTENSIONS.contains(propName))
192:             return scramExtensions.map().get(propName);
193:         else
194:             return null;
195:     }
196: 
197:     @Override
198:     public boolean isComplete() {
199:         return state == State.COMPLETE;
200:     }
201: 
202:     @Override
203:     public byte[] unwrap(byte[] incoming, int offset, int len) {
204:         if (!isComplete())
205:             throw new IllegalStateException("Authentication exchange has not completed");
206:         return Arrays.copyOfRange(incoming, offset, offset + len);
207:     }
208: 
209:     @Override
210:     public byte[] wrap(byte[] outgoing, int offset, int len) {
211:         if (!isComplete())
212:             throw new IllegalStateException("Authentication exchange has not completed");
213:         return Arrays.copyOfRange(outgoing, offset, offset + len);
214:     }
215: 
216:     @Override
217:     public void dispose() {
218:     }
219: 
220:     private void setState(State state) {
221:         log.debug("Setting SASL/{} server state to {}", mechanism, state);
222:         this.state = state;
223:     }
224: 
225:     private void verifyClientProof(ClientFinalMessage clientFinalMessage) throws SaslException {
226:         try {
227:             byte[] expectedStoredKey = scramCredential.storedKey();
228:             byte[] clientSignature = formatter.clientSignature(expectedStoredKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
229:             byte[] computedStoredKey = formatter.storedKey(clientSignature, clientFinalMessage.proof());
230:             if (!MessageDigest.isEqual(computedStoredKey, expectedStoredKey))
231:                 throw new SaslException("Invalid client credentials");
232:         } catch (InvalidKeyException e) {
233:             throw new SaslException("Sasl client verification failed", e);
234:         }
235:     }
236: 
237:     private void clearCredentials() {
238:         scramCredential = null;
239:         clientFirstMessage = null;
240:         serverFirstMessage = null;
241:     }
242: 
243:     public static class ScramSaslServerFactory implements SaslServerFactory {
244: 
245:         @Override
246:         public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props, CallbackHandler cbh)
247:             throws SaslException {
248: 
249:             if (!ScramMechanism.isScram(mechanism)) {
250:                 throw new SaslException(String.format("Requested mechanism '%s' is not supported. Supported mechanisms are '%s'.",
251:                         mechanism, ScramMechanism.mechanismNames()));
252:             }
253:             try {
254:                 return new ScramSaslServer(ScramMechanism.forMechanismName(mechanism), props, cbh);
255:             } catch (NoSuchAlgorithmException e) {
256:                 throw new SaslException("Hash algorithm not supported for mechanism " + mechanism, e);
257:             }
258:         }
259: 
260:         @Override
261:         public String[] getMechanismNames(Map<String, ?> props) {
262:             Collection<String> mechanisms = ScramMechanism.mechanismNames();
263:             return mechanisms.toArray(new String[0]);
264:         }
265:     }
266: }
