411:     private void handleSaslToken(byte[] clientToken) throws IOException {
412:         if (!enableKafkaSaslAuthenticateHeaders) {
413:             byte[] response = saslServer.evaluateResponse(clientToken);
414:             if (saslServer.isComplete()) {
415:                 reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
416:                 if (reauthInfo.reauthenticating())
417:                     reauthInfo.ensurePrincipalUnchanged(principal());
418:             }
419:             if (response != null) {
420:                 netOutBuffer = ByteBufferSend.sizePrefixed(ByteBuffer.wrap(response));
421:                 flushNetOutBufferAndUpdateInterestOps();
422:             }
423:         } else {
424:             ByteBuffer requestBuffer = ByteBuffer.wrap(clientToken);
425:             RequestHeader header = RequestHeader.parse(requestBuffer);
426:             ApiKeys apiKey = header.apiKey();
427:             short version = header.apiVersion();
428:             RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(),
429:                     KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
430:             RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
431:             if (apiKey != ApiKeys.SASL_AUTHENTICATE) {
432:                 IllegalSaslStateException e = new IllegalSaslStateException("Unexpected Kafka request of type " + apiKey + " during SASL authentication.");
433:                 buildResponseOnAuthenticateFailure(requestContext, requestAndSize.request.getErrorResponse(e));
434:                 throw e;
435:             }
436:             if (!apiKey.isVersionSupported(version)) {
437:                 // We cannot create an error response if the request version of SaslAuthenticate is not supported
438:                 // This should not normally occur since clients typically check supported versions using ApiVersionsRequest
439:                 throw new UnsupportedVersionException("Version " + version + " is not supported for apiKey " + apiKey);
440:             }
441:             /*
442:              * The client sends multiple SASL_AUTHENTICATE requests, and the client is known
443:              * to support the required version if any one of them indicates it supports that
444:              * version.
445:              */
446:             if (!reauthInfo.connectedClientSupportsReauthentication)
447:                 reauthInfo.connectedClientSupportsReauthentication = version > 0;
448:             SaslAuthenticateRequest saslAuthenticateRequest = (SaslAuthenticateRequest) requestAndSize.request;
449: 
450:             try {
451:                 byte[] responseToken = saslServer.evaluateResponse(
452:                         Utils.copyArray(saslAuthenticateRequest.data().authBytes()));
453:                 if (reauthInfo.reauthenticating() && saslServer.isComplete())
454:                     reauthInfo.ensurePrincipalUnchanged(principal());
455:                 // For versions with SASL_AUTHENTICATE header, send a response to SASL_AUTHENTICATE request even if token is empty.
456:                 byte[] responseBytes = responseToken == null ? new byte[0] : responseToken;
457:                 long sessionLifetimeMs = !saslServer.isComplete() ? 0L
458:                         : reauthInfo.calcCompletionTimesAndReturnSessionLifetimeMs();
459:                 sendKafkaResponse(requestContext, new SaslAuthenticateResponse(
460:                         new SaslAuthenticateResponseData()
461:                         .setErrorCode(Errors.NONE.code())
462:                         .setAuthBytes(responseBytes)
463:                         .setSessionLifetimeMs(sessionLifetimeMs)));
464:             } catch (SaslAuthenticationException e) {
465:                 buildResponseOnAuthenticateFailure(requestContext,
466:                         new SaslAuthenticateResponse(
467:                                 new SaslAuthenticateResponseData()
468:                                 .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
469:                                 .setErrorMessage(e.getMessage())));
470:                 throw e;
471:             } catch (SaslException e) {
472:                 KerberosError kerberosError = KerberosError.fromException(e);
473:                 if (kerberosError != null && kerberosError.retriable()) {
474:                     // Handle retriable Kerberos exceptions as I/O exceptions rather than authentication exceptions
475:                     throw e;
476:                 } else {
477:                     // DO NOT include error message from the `SaslException` in the client response since it may
478:                     // contain sensitive data like the existence of the user.
479:                     String errorMessage = "Authentication failed during "
480:                             + reauthInfo.authenticationOrReauthenticationText()
481:                             + " due to invalid credentials with SASL mechanism " + saslMechanism;
482:                     buildResponseOnAuthenticateFailure(requestContext, new SaslAuthenticateResponse(
483:                             new SaslAuthenticateResponseData()
484:                             .setErrorCode(Errors.SASL_AUTHENTICATION_FAILED.code())
485:                             .setErrorMessage(errorMessage)));
486:                     throw new SaslAuthenticationException(errorMessage, e);
487:                 }
488:             }
489:         }
490:     }
