551:     private String handleHandshakeRequest(RequestContext context, SaslHandshakeRequest handshakeRequest) throws IOException, UnsupportedSaslMechanismException {
552:         String clientMechanism = handshakeRequest.data().mechanism();
553:         short version = context.header.apiVersion();
554:         if (version >= 1)
555:             this.enableKafkaSaslAuthenticateHeaders(true);
556:         if (enabledMechanisms.contains(clientMechanism)) {
557:             LOG.debug("Using SASL mechanism '{}' provided by client", clientMechanism);
558:             sendKafkaResponse(context, new SaslHandshakeResponse(
559:                     new SaslHandshakeResponseData().setErrorCode(Errors.NONE.code()).setMechanisms(enabledMechanisms)));
560:             return clientMechanism;
561:         } else {
562:             LOG.debug("SASL mechanism '{}' requested by client is not supported", clientMechanism);
563:             buildResponseOnAuthenticateFailure(context, new SaslHandshakeResponse(
564:                     new SaslHandshakeResponseData().setErrorCode(Errors.UNSUPPORTED_SASL_MECHANISM.code()).setMechanisms(enabledMechanisms)));
565:             throw new UnsupportedSaslMechanismException("Unsupported SASL mechanism " + clientMechanism);
566:         }
567:     }
